SourceCode.Declaration:
[
DataContractAttribute
]
public class ETG_ContractTrackingContract
{
    TransDate           fromDate;
    TransDate           toDate;


}

Method.Source:
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("From Date")),
    SysOperationHelpTextAttribute(literalStr("Enter the from date for contract tracking"))
]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("To Date")),
    SysOperationHelpTextAttribute(literalStr("Enter the to date for contract tracking"))
]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

/// <summary>
/// Validates the contract parameters
/// </summary>
/// <returns>True if valid, false otherwise</returns>
public boolean validate()
{
    boolean ret = true;

    if (!fromDate)
    {
        ret = checkFailed("From date is required");
    }
    else if (!toDate)
    {
        ret = checkFailed("To date is required");
    }

    else if (fromDate > toDate)
    {
        ret = checkFailed("From date should not be greater than To date");
    }

    return ret;
}
